import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import './App.css';
import Nav from './components/Navigation';

function App() {
  return (
    <Router>
            <Nav />
            <Routes>
              <Route 
                path="/" 
                element={<Home />} 
              />
              <Route 
                path="/login" 
                element={<Login />} 
              />
              <Route 
                path="/signup" 
                element={<Signup />} 
              />
                <Route 
                path="/profile" 
                element={<Profile />} 
              />
              <Route
              path="/singleAnime"
              element={<SingleAnime/>}
              />
              <Route
              path="/singleManga"
              element={<SingleManga/>}
              />
              <Route 
                path="*" 
                element={<NoMatch />}
              />
            </Routes>
      </Router>
  );
}

export default App;
